import{c as p,Q as s,j as t,m as i}from"./chunks/framework.D9IbVcwA.js";const u=JSON.parse('{"title":"028-fs-ext2-1 · Ext2 文件系统","description":"","frontmatter":{"title":"028-fs-ext2-1 · Ext2 文件系统"},"headers":[],"relativePath":"tutorial/028-fs-ext2-1.md","filePath":"tutorial/028-fs-ext2-1.md","lastUpdated":1779686691000}'),a={name:"tutorial/028-fs-ext2-1.md"};function n(o,e,l,r,d,c){return s(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="_028-1-tutorial-从-vfs-到-ext2——挂载真实磁盘文件系统" tabindex="-1">028-1 Tutorial: 从 VFS 到 ext2——挂载真实磁盘文件系统 <a class="header-anchor" href="#_028-1-tutorial-从-vfs-到-ext2——挂载真实磁盘文件系统" aria-label="Permalink to &quot;028-1 Tutorial: 从 VFS 到 ext2——挂载真实磁盘文件系统&quot;">​</a></h1><blockquote><p>标签：ext2、文件系统、AHCI、磁盘布局、Superblock 前置：<a href="./027-fs-vfs-1">027_fs_vfs</a></p></blockquote><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>写完 027 tag 的 VFS 之后，我们手上有了一套看起来还算像样的文件系统框架——</p><p>FileSystem 抽象基类、Inode/InodeOps 接口、挂载表、路径解析。</p><p>但说实话，这套东西跑的其实只有一个后端：Ramdisk。</p><p>而 Ramdisk 是什么？说白了就是把一块内存区域假装成文件系统。</p><p>断电即消失，写入无处安放，容量受限于内核启动时加载的那点数据。</p><p>这在教学阶段够用，但如果我们想让操作系统真正&quot;可用&quot;——</p><p>能持久存储文件、能从磁盘启动用户程序——</p><p>就必须对接一个真正的磁盘文件系统。</p><p>这不是什么可有可无的锦上添花，而是从&quot;能跑的 demo&quot;到&quot;可用的 OS&quot;的分水岭。</p><p>想想看，一个操作系统的文件系统如果断电就没了，那它和一段普通的演示程序有什么本质区别？</p><p>接下来问题来了：选哪个文件系统？</p><p>FAT32 简单但结构丑陋（FAT 表本质上就是一个巨大的数组），</p><p>NTFS 闭源且复杂到让人绝望，</p><p>ZFS/Btrfs 对一个教学内核来说完全是 overkill。</p><p>经过反复权衡，我们选择了 ext2——The Second Extended Filesystem。</p><p>这不是一个随意的选择，ext2 在操作系统开发社区中被公认为</p><p>&quot;第一个真正的文件系统&quot;的最佳学习对象。</p><p>它的数据结构清晰、文档完善</p><p>（OSDev Wiki 上的 ext2 条目是少数能直接当 spec 用的页面），</p><p>而且 Linux、SerenityOS 等知名项目都有完整的 ext2 实现可供参考对比。</p><p>ext2 由 Rémy Card 等人在 1993 年设计，</p><p>作为 ext（Extended Filesystem）的继任者。</p><p>虽然如今 Linux 桌面和服务器已经全面转向 ext4，</p><p>但 ext2 的核心数据结构与 ext3/ext4 几乎完全相同——</p><p>区别主要在于 ext3 加了日志（journal），ext4 加了 extent 和更大的块支持。</p><p>所以学会了 ext2，理解 ext3/ext4 也就是多几层概念的事情。</p><h2 id="环境说明" tabindex="-1">环境说明 <a class="header-anchor" href="#环境说明" aria-label="Permalink to &quot;环境说明&quot;">​</a></h2><p>这次的起点是 027_fs_vfs tag，在它的基础上我们新增了三个核心文件：</p><ul><li><code>kernel/fs/ext2_types.hpp</code>（磁盘数据结构定义，约 310 行）</li><li><code>kernel/fs/ext2.hpp</code>（驱动类声明，约 476 行）</li><li><code>kernel/fs/ext2.cpp</code>（驱动实现，约 1810 行）</li></ul><p>工具链不变——GCC 14 + CMake + QEMU，</p><p>但这次我们需要第二块磁盘：</p><p>一块 4MB 的 ext2 镜像挂载在 AHCI port 1 上。</p><p>创建镜像的脚本在 <code>scripts/create_ext2_disk.sh</code>，</p><p>使用了 mkfs.ext2 和 debugfs 两个来自 e2fsprogs 的工具。</p><p>如果你用的是 Debian/Ubuntu，<code>sudo apt install e2fsprogs</code> 就能装上。</p><p>如果你用的是 Arch Linux，这些工具默认就在 <code>e2fsprogs</code> 包里。</p><h2 id="第一步——理解-ext2-的磁盘布局-块、块组与层级结构" tabindex="-1">第一步——理解 ext2 的磁盘布局：块、块组与层级结构 <a class="header-anchor" href="#第一步——理解-ext2-的磁盘布局-块、块组与层级结构" aria-label="Permalink to &quot;第一步——理解 ext2 的磁盘布局：块、块组与层级结构&quot;">​</a></h2><p>在写一行代码之前，我们必须先搞清楚 ext2 是怎么把数据组织在磁盘上的。</p><p>ext2 的基本 I/O 单位是&quot;块&quot;（block），</p><p>大小可以是 1024、2048 或 4096 字节——</p><p>具体值由 Superblock 中的 <code>s_log_block_size</code> 字段决定，</p><p>计算公式是 <code>block_size = 1024 &lt;&lt; s_log_block_size</code>。</p><p>这个设计比直接存一个整数稍微绕了一点，</p><p>但好处是 0 代表 1024、1 代表 2048、2 代表 4096，</p><p>用移位就能算出来，CPU 友好。</p><p>你可能会问为什么不直接存块大小的值？</p><p>原因在于 ext2 设计时考虑的是&quot;最少存储空间表达最大信息量&quot;——</p><p>一个 32 位整数如果直接存 1024/2048/4096 太浪费了，</p><p>而用指数表示只需要 2 个 bit 就能区分所有合法的块大小。</p><p>ext2 把整个磁盘空间划分成若干&quot;块组&quot;（Block Group），</p><p>每个块组包含自己的数据块位图（block bitmap）、</p><p>inode 位图（inode bitmap）、</p><p>inode 表（inode table）</p><p>和数据块区域。</p><p>这种设计不是随便画的——</p><p>它的核心目的是把&quot;属于同一个文件的元数据和数据&quot;在物理上放在一起，</p><p>减少磁盘寻道时间。</p><p>在机械硬盘时代这个优化非常重要，即使在 SSD 时代也依然有益于局部性。</p><p>每个块组内部的结构顺序是固定的：</p><p>首先是 block bitmap（占一个块），</p><p>然后是 inode bitmap（占一个块），</p><p>然后是 inode table（占若干块，具体取决于每组有多少 inode），</p><p>最后是数据块区域。</p><p>磁盘的第一个 1024 字节是引导块（boot block），</p><p>从字节 1024 开始是 Superblock。</p><p>对于 1024 字节块大小的情况，Superblock 位于 block 1</p><p>（block 0 是引导块）；</p><p>对于更大的块大小，Superblock 起始位置仍然是字节 1024</p><p>但它位于 block 0 的后半部分。</p><p>紧跟在 Superblock 之后的是块组描述符表</p><p>（Block Group Descriptor Table, BGDT），</p><p>每个条目 32 字节，描述一个块组的元数据位置。</p><p>这个布局可以用一张简单的图来表示：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Disk layout (1024-byte blocks):</span></span>
<span class="line"><span>  Block 0:  Boot block (1024 bytes, unused by ext2)</span></span>
<span class="line"><span>  Block 1:  Superblock (1024 bytes)</span></span>
<span class="line"><span>  Block 2+: Block Group Descriptor Table</span></span>
<span class="line"><span>  Block N:  Block Group 0: [Block Bitmap][Inode Bitmap][Inode Table][Data Blocks]</span></span>
<span class="line"><span>  Block M:  Block Group 1: [Block Bitmap][Inode Bitmap][Inode Table][Data Blocks]</span></span>
<span class="line"><span>  ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>你会发现，每个块组都有自己独立的 bitmap 和 inode table。</p><p>这意味着当你在某个目录下创建文件时，</p><p>ext2 可以把这个文件的 inode 和数据块都分配在同一个块组内，</p><p>大大减少了磁头的移动距离。</p><h2 id="第二步——设计对比-linux、serenityos-与-cinux-的不同路线" tabindex="-1">第二步——设计对比：Linux、SerenityOS 与 Cinux 的不同路线 <a class="header-anchor" href="#第二步——设计对比-linux、serenityos-与-cinux-的不同路线" aria-label="Permalink to &quot;第二步——设计对比：Linux、SerenityOS 与 Cinux 的不同路线&quot;">​</a></h2><p>理解了 ext2 的磁盘布局之后，</p><p>我们来看看其他操作系统是怎么实现 ext2 驱动的，</p><p>这对理解我们自己的设计选择非常有帮助。</p><h3 id="linux-内核的-ext2-实现" tabindex="-1">Linux 内核的 ext2 实现 <a class="header-anchor" href="#linux-内核的-ext2-实现" aria-label="Permalink to &quot;Linux 内核的 ext2 实现&quot;">​</a></h3><p>Linux 内核的 ext2 实现（<code>fs/ext2/</code>）是生产级的，</p><p>代码分散在十几个文件里——</p><p>super.c 处理挂载和超级块，inode.c 处理 inode 读写，</p><p>balloc.c 和 ialloc.c 分别负责块分配和 inode 分配，</p><p>dir.c 处理目录操作。</p><p>Linux 使用 <code>buffer_head</code> 子系统来管理磁盘块的缓存和 I/O 调度——</p><p>每次读取一个块时，buffer_head 层会先检查页缓存（page cache），</p><p>命中就直接返回，未命中才发起真正的磁盘 I/O。</p><p>这意味着在 Linux 中连续两次读取同一个块，第二次几乎是免费的。</p><p>Linux 的 ext2 还实现了 Orlov 块分配器</p><p>（在 <code>fs/ext2/ialloc.c</code> 中），</p><p>它的目标是在创建新文件时智能地选择块组，</p><p>使得相关文件（比如同一个目录下的文件）尽量放在同一个块组里，</p><p>减少碎片化。</p><p>此外 Linux 完整支持三级间接块</p><p>（最大文件可达 2TB+），</p><p>使用 per-CPU 计数器来跟踪空闲块/inode 数量以避免锁竞争，</p><p>还实现了文件预读（readahead）来优化顺序读性能。</p><h3 id="serenityos-的-ext2-实现" tabindex="-1">SerenityOS 的 ext2 实现 <a class="header-anchor" href="#serenityos-的-ext2-实现" aria-label="Permalink to &quot;SerenityOS 的 ext2 实现&quot;">​</a></h3><p>SerenityOS 的 ext2 实现</p><p>（<code>Kernel/FileSystem/Ext2FS/</code>）</p><p>走的是 C++ 面向对象路线，和 Cinux 在架构上最为相似。</p><p>它定义了一个 <code>BlockBasedFileSystem</code> 基类</p><p>来抽象&quot;以块为单位进行 I/O&quot;的文件系统，</p><p>然后 <code>Ext2FS::FileSystem</code> 继承自它。</p><p>SerenityOS 最有意思的设计是 <code>BlockView</code>——</p><p>一个 RAII 风格的块访问封装，</p><p>使用时就像打开一个智能指针，用完自动释放回缓存。</p><p>这种设计把&quot;获取块→使用块→释放块&quot;的生命周期管理</p><p>变成了类型系统的一部分，非常优雅。</p><p>SerenityOS 还直接复用了 Linux 的 <code>ext2_fs.h</code> 磁盘定义</p><p>（通过 copy），</p><p>并且支持多种文件系统后端——</p><p>Ext2、FAT、ISO9660、RAMFS、ProcFS、SysFS 等——</p><p>都通过统一的 VFS 层暴露给用户态。</p><p>不过 SerenityOS 的 ext2 实现比 Cinux 复杂得多，</p><p>光是 Inode 类就有几百行代码，处理了符号链接、扩展属性等特性。</p><h3 id="cinux-的定位" tabindex="-1">Cinux 的定位 <a class="header-anchor" href="#cinux-的定位" aria-label="Permalink to &quot;Cinux 的定位&quot;">​</a></h3><p>相比之下，Cinux 的 ext2 驱动介于 xv6 和 SerenityOS 之间——</p><p>架构上类似 SerenityOS 的 C++ 风格</p><p>（Ext2 继承 FileSystem，通过静态 InodeOps 函数指针表分发操作），</p><p>但 I/O 层面更接近 xv6 的极简风格：</p><p>一个物理页的 DMA buffer，每次只读一个块，没有块缓存。</p><p>这意味着频繁访问同一个块会导致反复的磁盘 I/O，</p><p>性能代价很大，但代码复杂度大大降低——</p><p>对教学内核来说这是一个合理的取舍。</p><h2 id="第三步——创建-ext2-磁盘镜像" tabindex="-1">第三步——创建 ext2 磁盘镜像 <a class="header-anchor" href="#第三步——创建-ext2-磁盘镜像" aria-label="Permalink to &quot;第三步——创建 ext2 磁盘镜像&quot;">​</a></h2><p>理解了设计之后，我们先把测试用的磁盘镜像准备好。</p><p><code>scripts/create_ext2_disk.sh</code> 做的事情很简单但很精巧——</p><p>用 dd 创建一个 4MB 的零填充镜像，</p><p>用 mkfs.ext2 格式化为 ext2</p><p>（指定 1024 字节块大小、不启用任何扩展特性、128 个 inode），</p><p>然后用 debugfs 往里写入测试文件。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">IMAGE_SIZE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">4</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">BLOCK_SIZE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1024</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> if=/dev/zero</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> of=&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$OUTPUT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bs=1M</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> count=&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$IMAGE_SIZE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/dev/null</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkfs.ext2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$BLOCK_SIZE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -O</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> none</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -N</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 128</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$OUTPUT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/dev/null</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;&amp;1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>debugfs 是 e2fsprogs 自带的调试工具，</p><p>它可以在不挂载文件系统的情况下直接操作 ext2 镜像的内部结构——</p><p>创建目录、写入文件、修改 inode，非常适合在构建脚本中使用。</p><p>脚本创建的目录结构包括 <code>/etc/motd</code>（欢迎信息）和 <code>/hello.txt</code>（测试文件），</p><p>如果提供了 shell ELF 路径还会创建 <code>/bin/sh</code>。</p><p>这里有两个细节值得注意。</p><p>第一，<code>-O none</code> 参数禁用了所有 ext2 扩展特性</p><p>（稀疏超级块、文件类型等），</p><p>让镜像结构尽可能简单。</p><p>第二，<code>-N 128</code> 指定只创建 128 个 inode，</p><p>对于 4MB 镜像来说绰绰有余而且节省空间。</p><p>创建完镜像之后，你可以用 <code>dumpe2fs ext2.img</code> 来查看文件系统的详细信息——</p><p>块大小、inode 数量、块组布局一目了然。</p><p>这个工具在调试 ext2 驱动的时候也非常有用，</p><p>当你怀疑某个数据结构读错了，可以先用 dumpe2fs 确认磁盘上的正确值。</p><h2 id="第四步——qemu-配置-第二块-ahci-磁盘" tabindex="-1">第四步——QEMU 配置：第二块 AHCI 磁盘 <a class="header-anchor" href="#第四步——qemu-配置-第二块-ahci-磁盘" aria-label="Permalink to &quot;第四步——QEMU 配置：第二块 AHCI 磁盘&quot;">​</a></h2><p>镜像创建好了，接下来要把它挂到 QEMU 的 AHCI 控制器的第二个端口上。</p><p>在 QEMU 启动参数中，我们添加一块新磁盘并连接到 AHCI 的 port 1</p><p>（port 0 留给了 ramdisk 或者启动盘）。</p><p>具体配置取决于你的 QEMU 启动脚本，</p><p>核心是在 <code>-drive</code> 参数中指定 <code>file=ext2.img</code></p><p>并且确保它连接到 AHCI 控制器的第二个端口。</p><p>这样在内核中，AHCI 驱动枚举到两个端口后，</p><p>我们用 <code>Ext2 ext2(ahci, 1)</code> 把 ext2 驱动绑定到 port 1，</p><p>然后调用 <code>ext2.mount()</code> 就能开始读取文件系统元数据了。</p><p>这块 ext2 磁盘在 Cinux 中是一个独立于 ramdisk 的存储设备。</p><p>挂载成功后，我们通过 <code>vfs_mount_add(&quot;/&quot;, &amp;ext2)</code></p><p>把 ext2 根目录挂载到 VFS 的某个挂载点上，</p><p>之后所有的文件操作就会透明地走到 ext2 驱动里。</p><p>如果你回头看 027 tag 的 VFS 设计，</p><p>会发现这套机制正好被用上了——</p><p>FileSystem 抽象基类的 <code>mount()</code> 和 <code>lookup()</code></p><p>就是为这种场景设计的。</p><p>VFS 层存在的意义，现在终于体现出来了：</p><p>上层代码（syscall、shell）不需要知道底层是 Ramdisk 还是 ext2，</p><p>它只要调用 <code>vfs_lookup(path)</code> 就行。</p><h2 id="收尾" tabindex="-1">收尾 <a class="header-anchor" href="#收尾" aria-label="Permalink to &quot;收尾&quot;">​</a></h2><p>这一篇我们完成了从&quot;为什么要做 ext2&quot;到&quot;怎么准备测试环境&quot;的全部铺垫。</p><p>磁盘镜像有了，QEMU 配置好了，ext2 的磁盘布局也理清楚了。</p><p>我们也对比了 Linux、SerenityOS 和 Cinux 三种不同的 ext2 实现路线，</p><p>理解了为什么 Cinux 选择&quot;简单但正确&quot;的设计策略。</p><p>下一篇我们就要真正深入代码——</p><p>从 AHCI 读取 Superblock、验证魔数、计算块大小、</p><p>加载 BGDT、读取根 inode。</p><p>这些都是 ext2 驱动的核心初始化流程，</p><p>每一步都有数学推导和陷阱等着我们。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li>OSDev Wiki: <a href="https://wiki.osdev.org/Ext2" target="_blank" rel="noreferrer">ext2</a> — 完整的 ext2 磁盘数据结构参考</li><li>Linux ext2 实现: <a href="https://github.com/torvalds/linux/tree/master/fs/ext2" target="_blank" rel="noreferrer">fs/ext2/</a></li><li>SerenityOS ext2 实现: <a href="https://github.com/SerenityOS/serenity/tree/master/Kernel/FileSystem/Ext2FS" target="_blank" rel="noreferrer">Kernel/FileSystem/Ext2FS/</a></li><li>e2fsprogs: <a href="https://github.com/tytso/e2fsprogs" target="_blank" rel="noreferrer">e2fsprogs GitHub</a> — mkfs.ext2 和 debugfs 的源码仓库</li><li>Rémy Card, Theodore Ts&#39;o, Stephen Tweedie, &quot;Design and Implementation of the Second Extended Filesystem&quot;, Proceedings of the First Dutch International Symposium on Linux, 1994</li><li>The Linux Programming Interface (Kerrisk), Chapter 14: File I/O Buffering</li><li>Kleiman, &quot;Vnodes: An Architecture for Multiple File System Types in Sun UNIX&quot;, USENIX 1986</li></ul>`,188)])])}const k=p(a,[["render",n]]);export{u as __pageData,k as default};
